-- ==============================================
-- Freestyle Highline – trick data import
-- ==============================================

insert into positions (name) values
  ('BACK'),
  ('CHEST'),
  ('DOUBLE DROPKNEE'),
  ('DROPKNEE'),
  ('EXPOSURE'),
  ('KOREAN'),
  ('LEASH'),
  ('NEVERMIND'),
  ('ROCKET'),
  ('SHOULDER'),
  ('SOFA'),
  ('SOUP'),
  ('STAND'),
  ('YISUS')
on conflict (name) do nothing;

with pos as (select id, name from positions)
insert into tricks (
  given_name, technical_name, difficulty_tier,
  date_submitted, date_performed, original_performer,
  description, tips, video_link,
  start_position_id, end_position_id, status
)
select
  t.given_name, t.technical_name, t.difficulty_tier,
  t.date_submitted::timestamptz, t.date_performed::date,
  t.original_performer, t.description, t.tips, t.video_link,
  sp.id, ep.id,
  'approved'
from (values
  ('Yodel Roll','Expo 360 to Back Yoda Roll','8','2022-12-03 20:14:59','2022-04-17','Tim Odermatt','From Exposure do a 360 and grab the line. Then go into a Back Yoda Roll.',null,'https://www.instagram.com/p/CcdNbmCAWsw/','EXPOSURE','EXPOSURE'),
  ('Nevermind 360',null,'7','2022-12-03 20:20:01','2022-05-26','Tim Odermatt','From Nevermind go up spinning frontside 360 and land back in your normal stance.',null,'https://www.instagram.com/p/CeCNKq5Fqyc/','NEVERMIND','STAND'),
  ('Infinity','Neverending Yoda Rolls','9','2022-12-03 20:25:31','2022-01-07','Tim Odermatt','Start out as you would for a one bounce Yoda Roll but then keep rolling. Never stop!','Tim invented this trick when going for a one bounce Double Back Yoda Roll.','https://www.instagram.com/p/CYcI_IRAxQK/','EXPOSURE','EXPOSURE'),
  ('Double Back Han Solo',null,'8','2022-12-03 20:29:20','2022-06-06','Tim Odermatt','Similar to a Double Back Yoda Roll but grabbing the leash instead of the line.',null,'https://www.instagram.com/p/CejUEcrlg2K/','EXPOSURE','EXPOSURE'),
  ('Soup Backflop','Can of Soup to Backflop','8','2022-12-03 20:35:03','2022-06-18','Tim Odermatt','Do a Can of Soup into a Backflop in the same bounce.',null,'https://www.instagram.com/p/Ce8WJ4YlvTr/','SOUP','KOREAN'),
  ('Backflip Late 180',null,'9','2022-12-03 20:43:40','2022-07-24','Tim Odermatt','Do a Backflip but then passing Exposure you add a 180 before landing the trick.','Think about landing the normal Backflip in switch so when you add the 180 you are back in your normal stance.','https://www.instagram.com/p/CgZsOA1l2eG/','STAND','STAND'),
  ('Barrelflop','Barrel Roll to Backflop','8','2022-12-03 20:45:37','2022-07-15','Tim Odermatt','Do a Barrel Roll and add a late Backflop.',null,'https://www.instagram.com/p/Cge6C4VFUPm/','STAND','KOREAN'),
  ('Yodermatt','Double Back Yoda Roll 180','9','2022-12-03 20:54:58','2022-08-26','Tim Odermatt','Double Back Yoda Roll with a 180 in the second Roll.',null,'https://www.instagram.com/p/Ch8Ca0GPEOG/','EXPOSURE','EXPOSURE'),
  ('Legolas','NH Shapeshifter to Feet','9','2022-12-03 21:06:08','2022-09-24','Tim Odermatt','Jump into the leash doing a frontflip from Exposure then use your foot to step into the leash and then back on the line.',null,'https://www.instagram.com/p/Ci5NrdeJqa6/','EXPOSURE','EXPOSURE'),
  ('Triple Front Yoda Roll',null,'9','2022-12-03 21:27:31','2022-07-12','Emil Breuer','Three Front Yoda Rolls in one bounce.',null,'https://www.instagram.com/p/Cf6TRhogHtO/','EXPOSURE','EXPOSURE'),
  ('Nevermindhty','Back Almighty from Nevermind','7','2022-12-03 21:31:33','2022-07-07','Emil Breuer','Start like a normal Nevermind but then push into the line with the foot that is already on the line to create momentum into a back roll. Use your second foot to hook the line and finish with a Back Almighty.',null,'https://www.instagram.com/p/CggrqR7gV5j/','NEVERMIND','EXPOSURE'),
  ('Catwheel','From sofa to handstand to sofa','4','2023-07-28 14:24:15','2023-05-27','Tomáš Michel','Starting in sofa with ring front you, catch the line on your side and in 75% of way up in the bounce push to handstand to you are fully extended on the top of the bounce, after you continue in motion to side landing in sofa.','Play with handstand from sofa and drop it to leashfall to get feeling of this position and land trick in side rotation.','https://www.instagram.com/reel/CvPiE2goN-l/','SOFA','SOFA'),
  ('Catwheel from feet','From feet to handstand to sofa','6','2023-07-28 14:34:32','2023-07-27','Tomáš Michel','Before top of bounce you lean to catch line and push to handstand on the top, continue in side motion to drop it to sofa','You should be familiar with basic catwheel and feel comfortable to drop trick from feet.','https://www.instagram.com/reel/CvPiE2goN-l/','STAND','SOFA'),
  ('Catwheel to feet','From sofa to handstand to exposure','7','2023-07-28 14:38:04','2023-05-29','Tomáš Michel','Starting in sofa push to handstand continue side motion landing to feet.','Have solid Catwheel','https://www.instagram.com/reel/CvPiE2goN-l/','SOFA','EXPOSURE'),
  ('Vortex','Triplo shoulder roll','9','2023-08-29 22:00:36','2021-12-01','Lucas clemente Pereira','Ter o double sholder roll na base','Executar com muita força','https://www.instagram.com/tv/CYTUaA5uwWa/','SHOULDER','SHOULDER'),
  ('Sushi-Flip','Sushi Backflip','10','2025-03-05 16:51:47','2022-08-07','Ian Eisenberg','Start with an early Sushi and add a Backflip to it',null,'https://www.instagram.com/p/Cg8_eXWLmXw/','STAND','STAND'),
  ('No-Hands Backflip',null,'9','2025-03-05 17:04:41','2022-08-08','Ian Eisenberg','Like a regular Backflip but without using your hands.',null,'https://www.instagram.com/p/Cg_eTDJLsZ6/','STAND','STAND'),
  ('Chill','Backbounce roll half spiral to feet','6','2025-03-05 17:05:22','2022-01-19','Sakalomo','Start from backbounce and grab the line with one hand. Before the top of the bounce throw yourself to the side of the hand that grabs the line. Do a roll below the line, take with both hands and put your feet.','Timing is key. When you throw yourself think of kicking up with your knees/feet to initiate the rotation.','https://www.instagram.com/reel/CY6eIm2K4_M/','BACK','STAND'),
  ('BS 360 Rocket Mount',null,'7','2025-03-05 17:07:36','2022-08-14','Ian Eisenberg','Rocket Mount with a 360 spinning to your backside.',null,'https://www.instagram.com/p/ChPQYxLMAMA/','ROCKET','EXPOSURE'),
  ('Sharkbite','Rocket Line Bite','4','2025-03-05 17:21:01','2022-08-25','Ian Eisenberg','From Rocket you pull yourself up so you''re able to bite the line and let go with the hands. Then grab the line again and drop back to Rocket.','Watch out to not bite your lips','https://www.instagram.com/p/ChsA7RvrV7m/','ROCKET','ROCKET'),
  ('Gorilla','Makako to feet with an extra back yoda roll','10','2025-03-05 17:28:31','2022-08-11','Sakalomo','Do a makako to feet and add an extra back yoda roll',null,'https://www.instagram.com/reel/ChH21QWAYmw/','NEVERMIND','EXPOSURE'),
  ('Batman','360 Rocket (over Bat-Hang)','5','2025-03-05 17:28:39','2022-08-25','Ian Eisenberg','You drop to Rocket slightly uncentered such that you can get some momentum by swinging to one side. From there you use the momentum to swing your legs to the other side and all the way up to hook the line with both feet (the Bat-Hang position), you let go with your hands and do a 360 under the line by regrabbing the line on the other side of your feet. Unhook your feet and land back in Rocket.',null,'https://www.instagram.com/p/ChsA7RvrV7m/','ROCKET','ROCKET'),
  ('Double Darth Vader',null,'10','2025-03-05 17:35:32','2022-08-25','Justin Wagers / Ian Eisenberg','It''s a Darth Vader with an extra roll.',null,'https://www.instagram.com/p/ChsjejWLu8d/','ROCKET','EXPOSURE'),
  ('Backalomo','Backbounce back almighty','9','2025-03-05 17:35:32','2022-10-17','Sakalomo','Do a backbounce, when you stand up hook your foot under the line to do a back almighty.',null,'https://www.instagram.com/reel/Cj0cYssPTO2/','BACK','EXPOSURE'),
  ('All-Nasty','Darkside Almighty','8','2025-03-05 17:40:11','2025-08-27','Ian Eisenberg','It''s a Darkside Roll but you let go with the hands while you''re doing the trick and hook with one foot to finish the trick like a Back Almighty.',null,'https://www.instagram.com/p/Chxgwo6s6g_/','SOFA','EXPOSURE'),
  ('A chuparla','Back shapeshifter','6','2025-03-05 17:40:13','2022-10-24','Sakalomo','Bounce hard, almost at the top of the bounce throw yourself backwards and do a backflip without touching the line. Put your hands up and grab the line to end in the rocket position.',null,'https://www.instagram.com/reel/CkGq5w3unmy/','EXPOSURE','ROCKET'),
  ('Sakalhombro','Chill to shoulder','7','2025-03-05 17:44:40','2022-12-23','Sakalomo','Do a chill but instead of landing on your feet go to shoulder.',null,'https://www.instagram.com/reel/Cmg1feNqD52/','BACK','SHOULDER'),
  ('540 Rocket to Sofa',null,'6','2025-03-05 17:45:31','2022-08-29','Ian Eisenberg','540 from Rocket to Sofa.',null,'https://www.instagram.com/p/Ch11yrdsUEG/','ROCKET','SOFA'),
  ('Eclipse','Backside orbital to feet.','8','2025-03-05 17:48:56','2023-01-10','Sakalomo','Just like an orbital to feet but throw the line to your backside. Land on your feet.','Timing is key when throwing the line.','https://www.instagram.com/reel/CnPMRSyDbqI/','STAND','STAND'),
  ('FS 360 Back Almighty',null,'8','2025-03-05 17:49:13','2022-09-01','Ian Eisenberg','Start with a frontside spin and then transition into the Back Almighty',null,'https://www.instagram.com/p/Ch99aJdpyUo/','STAND','STAND'),
  ('Chillin Vader','Chill to darth Vader','8','2025-03-06 13:49:28','2023-06-04','Sakalomo','Go to backbounce, do a chill but instead of going directly to feet do a darth vader motion to end in expo.',null,'https://www.instagram.com/reel/CuSHxPyt1Or/','BACK','EXPOSURE'),
  ('Never panic','Nevermind panic roll to feet','7','2025-03-06 13:56:28','2023-09-06','Sakalomo','Go to nevermind position. When you go up the bounce cross your foot and start a panic roll. Grab the line with both hands and put your feet.',null,'https://www.instagram.com/reel/Cw2TcR2MYwg/','NEVERMIND','EXPOSURE'),
  ('Backalomo 180','Backbounce back almighty 180','9','2025-03-06 14:03:26','2023-09-30','Sakalomo','Do a backbounce, when you go up hook your foot on the line and start a back almighty and when you are upside down start a 180 motion, en in feet.',null,'https://www.instagram.com/reel/Cxz3jG-MvFX/','BACK','EXPOSURE'),
  ('Reverse super mighty','Reverse super sonic but instead of a back yoda roll do a back almighty','9','2025-03-06 14:07:06','2023-09-30','Sakalomo','Do a reverse súper sonic but instead of doing a back yoda roll do a back almighty',null,'https://www.instagram.com/reel/Cxz3jG-MvFX/','ROCKET','EXPOSURE'),
  ('Emil Doppel-Wumms / david double sonic','Double super sonic. Rocket to double front yoda','10','2025-03-07 16:03:20','2023-10-04','Emil','Go to rocket, kick with your feet to start a super sonic and add an extra front yoda roll.',null,'https://www.instagram.com/reel/Cx_HE9SsTFX/','ROCKET','EXPOSURE'),
  ('Reverse darth Vader?','Makako to feet from rocket','10','2025-03-07 16:06:24','2023-10-04','Sakalomo','Go to rocket, then kick like you would for a Makako, rotate to land on your feet.',null,'https://www.instagram.com/reel/Cx_HE9SsTFX/','ROCKET','EXPOSURE'),
  ('King Kong','Makako feet to feet','10','2025-03-07 16:12:27','2024-01-21','Sakalomo','With a big bounce , grab the line while starting a roll backwards and from there kick like you would on a Makako. Put both feet on the line to land in expo',null,'https://www.instagram.com/reel/C2XluUNMUEV/','STAND','EXPOSURE'),
  ('Space eclipse to sofa','Eclipse without touching the line to sofa','8','2025-03-08 09:04:07','2024-09-08','Sakalomo','Do a eclipse bot don’t use your hands to move the line, let the high tension bring the line back down and go to sofa.','You need the right setup, some bungees and a lot of tensión on the line.','https://www.instagram.com/reel/C_p2waaMiEy/','STAND','SOFA'),
  ('Orbital to Double Drop Knee',null,'7','2025-03-08 09:06:14','2025-08-12','Ian Eisenberg','Just do everything as you would for the Orbital to Feet, but then go to Double Drop Knee (or Crook).',null,'https://www.instagram.com/p/Cjkb1LXrFci/','STAND','DOUBLE DROPKNEE'),
  ('Space sushi','A sushi pop no hands but leaving the line completely at some point','6','2025-03-08 09:09:57','2024-09-08','Sakalomo','When you go up before reaching the top let go of the line with your feet, the line should do a sushi pop motion, with the high tensión you should go up while the line stops touching your body. Aim again with your feet to step on the line.','You need the right setup up. Some bungees and a lot of tension on the line.','https://www.instagram.com/reel/C_p2waaMiEy/','STAND','STAND'),
  ('Shoulder Vader','Darth Vader from Shoulder','8','2025-03-08 09:14:31','2023-03-02','Ian Eisenberg','From Shoulder you initiate a Back Shoulder Roll but then you quickly let go with the far hand and turn more sideways. From there you finish with a Darth Vader.',null,'https://www.instagram.com/p/CpSmWVMNfNC/','SHOULDER','EXPOSURE'),
  ('Space sushi late 360','Sushi pop no hands from sofa late 360 to korean','8','2025-03-08 09:15:08','2024-09-08','Sakalomo','Do a sushi pop no hands to sofa, then when you stop touching the line do a late 360, grab the line and end in korean.','You need the right setup. Some bungees and a lot of tension on the line.','https://www.instagram.com/reel/C_p2waaMiEy/','STAND','KOREAN'),
  ('Impossible','Front almighty with no hook','10','2025-03-08 09:23:00','2024-09-08','Sakalomo','Do a front almighty but don’t use the foot to hook, just push the line to the side,  do the front flip and almost at the end of the rotation put your feet again to land in exposure.','You need the right setup. Some bungees and a lot of tension in the line.','https://www.instagram.com/reel/C_p2waaMiEy/','EXPOSURE','EXPOSURE'),
  ('Freak Nasty Roll','180 Sick Nasty Roll','7','2025-03-08 09:23:20','2023-04-17','Ian Eisenberg','Start with a Sick Nasty but add a 180 spin and finish with a Sick Nasty Roll',null,'https://www.instagram.com/p/CrJd3OYPBmz/','SOFA','SOFA'),
  ('Space eclipse to DDK','Space eclipse to double drop knee','10','2025-03-08 09:29:54','2024-09-08','Tim odermatt','Do a eclipse but don’t touch the line with your hands, once the line goes around you land on DDK','You need the right setup. Some bungees and a lot of tension.','https://www.instagram.com/reel/C_p2waaMiEy/','STAND','DROPKNEE'),
  ('Space eclipse','Eclipse fett to feet without using the hands.','10','2025-03-08 09:32:21','2024-09-08','Sakalomo','Do an eclipse but don’t touch the line with your hands. Once the line goes around out your feet again. The timing of the kick is key.',null,'https://www.instagram.com/reel/C_p2waaMiEy/','STAND','STAND'),
  ('Nerd Flip','180 Boomerang to Feet','9','2025-03-08 09:32:34','2023-05-13','Ian Eisenberg','Start with a normal Boomerang but instead of finishing it with a Sick Nasty Roll you finish it with a Rubiks Cube.',null,'https://www.instagram.com/p/CsL-QT4ucWR/','SOFA','EXPOSURE'),
  ('Kneisenvader','Darth Vader from Double Drop Knee','8','2025-03-08 09:37:49','2023-05-23','Ian Eisenberg','From Double Drop Knee Roll to the front until you are in the Rocket position and then use the momentum to finish with a Darth Vader',null,'https://www.instagram.com/p/Cslw6UhMg6d/','DOUBLE DROPKNEE','EXPOSURE'),
  ('Supervader','Supersonic to Darth Vader','9','2025-03-08 09:44:23','2023-07-03','Ian Eisenberg','Supersonic to Darth Vader... Not much else to say here!',null,'https://www.instagram.com/p/CuPrkp_Psrw/','ROCKET','EXPOSURE'),
  ('360 Supersonic',null,'9','2025-03-08 09:48:33','2023-07-13','Ian Eisenberg','Supersonic with a 360.',null,'https://www.instagram.com/p/C-GAIBNskkO/','ROCKET','EXPOSURE'),
  ('Sauron','Darth kako with extra yoda roll','10','2025-03-08 09:52:37','2024-10-10','Sakalomo','Go to nevermind, from there start a darth kako, on mice you get the roll add another yoda roll. Land in exposure',null,'https://www.instagram.com/reel/DA8FTrJs5jp/','NEVERMIND','EXPOSURE'),
  ('Space sakalorbital','Sakalorbital without touching the line with your hands','10','2025-03-08 09:57:57','2024-10-26','Sakalomo','Do a sakalorbital by kicking the line almost at the highest point of the bounce, rotate 180 let the line go around you and land again on your feet.',null,'https://www.instagram.com/reel/DBllnO2shH7/','STAND','STAND'),
  ('FS 540 Back Almighty',null,'9','2025-03-08 09:59:08','2023-07-30','Ian Eisenberg','Just watch the video.. It''s hard to describe :D',null,'https://www.instagram.com/p/CvUuGMUruQ3/','STAND','STAND'),
  ('Apocalypse','180 Eisenvader','9','2025-03-08 10:03:12','2023-08-06','Ian Eisenberg','Start with a normal Eisenvader but as soon as you are in the Rocket position you turn 180 and regrab the line to finish with a Reverse Rocket Mount.',null,'https://www.instagram.com/p/Cvmt1bFNrhg/','EXPOSURE','EXPOSURE'),
  ('180 Reverse Supersonic',null,'8','2025-03-08 10:06:11','2023-08-09','Samuel Volery','From Rocket you immediately spin 180 and regrab the line and then finish with a Reverse Supersonic.',null,'https://www.instagram.com/p/CvuP3_usiQD/','ROCKET','EXPOSURE'),
  ('Space lord','Front side 180 space eclipse to feet','10','2025-03-08 10:07:21','2024-12-03','Sakalomo','Do a space eclipse, when you kick the line rotate 180 to your front side, let the line go around you and land on your feet.',null,'https://www.instagram.com/reel/DDHFF09Mwmp/','STAND','STAND'),
  ('Space kako','Makako to feet but at one point not touching the line','10','2025-03-08 10:12:01','2024-12-19','Sakalomo','Go to nevermind, start a Makako but let go the line with your hands, do the rotation until your feet find the line, end in exposure.',null,'https://www.instagram.com/reel/DDwQUL2sEv1/','NEVERMIND','EXPOSURE'),
  ('Darth Maul','180 Exposure Backflip to Rocket','6','2025-03-08 10:13:50','2023-05-04','Logan Henning','From Expo you lean back as much as possible (as if you would do a back bridge) until you reach the line with one hand. Spin 180 and grab the line with the second hand, so that you end up in Rocket.',null,'https://www.instagram.com/p/Cr2RxoYLEPT/','EXPOSURE','ROCKET'),
  ('Front Nirvana','360 Front Sofa Roll to Feet','6','2025-03-08 10:19:01','2023-08-23','Ian Eisenberg','From Sofa you grab the line with both hands on the side and initiate a roll to the front. You immediately go into Belly and keep rolling but then add another 180, regrab one hand and land in Expo.',null,'https://www.instagram.com/p/CwTGyDcMBRb/','SOFA','EXPOSURE'),
  ('Beyblade','Leash Sideflip to Feet','8','2025-03-08 10:25:03','2023-09-10','Ian Eisenberg','Drop to Rocket but with the leash wrapped around your legs. Then do a sideflip using the momentum that the wrapped leash gives you and go to feet.',null,'https://www.instagram.com/p/CxBnTmsMDEA/','LEASH','EXPOSURE'),
  ('Space korean','Space orbital from korean','8','2025-03-09 08:48:06','2025-01-05','Tim Odermatt','From korean change your leg to butt and from there let the line go to do a space orbital. Use your leg to catch the line in korean.',null,'https://www.instagram.com/reel/DEcYgbmo4Sp/','KOREAN','KOREAN'),
  ('Chill Nasty Roll','Chill sick nasty roll','6','2025-03-09 09:06:47','2025-01-08','Sakalomo','Go to backbounce, grab the line below your back and throw your body to the same side of the grabbing hand, start a chill but instead of going to feet do a sick nasty roll.',null,'https://www.instagram.com/reel/DEkNWTOM8Ag/','BACK','SOFA'),
  ('Bs space lord','Back side 180 space orbital','10','2025-03-09 09:11:22','2025-01-23','Sakalomo','Do a space orbital but add a back side 180 to land facing the other anchor.',null,'https://www.instagram.com/reel/DFLv6RKMgkE/','STAND','STAND'),
  ('BS 180 Holy Crook',null,'9','2025-03-09 09:16:54','2023-10-08','Ian Eisenberg','180 Almighty to DDK with an extra DDK roll.',null,'https://www.instagram.com/p/CyJOOvGMv29/','EXPOSURE','DOUBLE DROPKNEE'),
  ('Rewind turtle','Front yoda double rewind','8','2025-03-09 09:25:57','2022-12-07','Tim Odermatt','Do a front yoda but change the direction of the spin to do a rewind and add another back yoda roll.',null,'https://www.instagram.com/reel/Cl3_96FrE-4/','EXPOSURE','EXPOSURE'),
  ('Nirvana Attack','No hands nirvana','8','2025-03-09 09:30:56','2023-01-13','Carlo Cozzio','Do a nirvana but instead of using your hands put hook your foot to spin.',null,'https://www.instagram.com/reel/CnXEHTsoKhC/','SOFA','EXPOSURE'),
  ('Full Orbit','FS 360 Orbital to Feet','8','2025-03-09 09:31:19','2023-10-23','Ian Eisenberg','Start with a FS 180 then grab the line and do an Orbital but spin another 180 before landing it.','Make sure to keep your body upright, otherwise you might end up just doing a Barrel Roll.','https://www.instagram.com/p/CyyRTTcMd-C/','STAND','STAND'),
  ('No soup 180','No hands can of soup 180','7','2025-03-09 09:35:30','2023-01-31','Tim Odermatt','Start form soup position, hook your foot to do a no soup and add a late 180.',null,'https://www.instagram.com/reel/CoFh3imuH_k/','SOUP','STAND'),
  ('180 Yisus Mount',null,'5','2025-03-09 09:35:50','2023-11-08','Ian Eisenberg','From Yisus let one hand go and step the same foot on the line, then put the second foot and let go with the second hand to land in Expo or Normal.',null,'https://www.instagram.com/p/CzZdIU_sr7I/','YISUS','EXPOSURE'),
  ('360 Tamatta Roll','Front Sofa Roll to Front Nirvana','8','2025-03-09 09:43:23','2023-12-21','Ian Eisenberg','Start with a Front Sofa Roll and then go into a Front Nirvana.',null,'https://www.instagram.com/p/C1IEj5vMzu6/','SOFA','EXPOSURE'),
  ('Flower Power','Korean 720 to feet','7','2025-03-09 09:45:37','2023-06-09','Tim Odermatt','From Korean start like you would do a flow but do 2 full spins, land on your feet.',null,'https://www.instagram.com/reel/CtRx_JwuWvS/','KOREAN','STAND'),
  ('Shoulder roll almighty','Shoulder roll almighty','9','2025-03-09 09:55:24','2023-08-04','Tim Odermatt','Do a shoulder roll to feet, instead of putting the second foot on the line do a hook to end with an almighty.',null,'https://www.instagram.com/reel/Cvhg5d0JQCf/','SHOULDER','STAND'),
  ('Sugar Cube','No-Hands Rubiks Cube','8','2025-03-09 09:57:49','2024-01-29','Ian Eisenberg','From Butt you spin backside and roll to your back, hook the line with your kneepit then put your other leg over the line so that you can step on the line with the hooking leg and finally put the second foot on the line.',null,'https://www.instagram.com/p/C2sml_5s4Bv/','SOFA','EXPOSURE'),
  ('BS 360 Back Dirty Sofa',null,'8','2025-03-09 10:01:12','2024-01-31','Ian Eisenberg','Just watch the video...',null,'https://www.instagram.com/p/C2xfEkwsvrz/','SOFA','EXPOSURE'),
  ('BS 180 Orbital to Feet',null,'7','2025-03-09 10:02:40','2024-02-02','Ian Eisenberg','Start with a BS 180 and then finish with an Orbital to Feet',null,'https://www.instagram.com/p/C222ouysWJa/','STAND','STAND'),
  ('Han Solo Rewind','Han Solo Rewind','7','2025-03-09 10:03:13','2023-08-28','Tim Odermatt','Do a Han Solo but instead of doing the full rotation change the direction of the roll to land in exposure.',null,'https://www.instagram.com/reel/Cwfrn3nsFWc/','EXPOSURE','EXPOSURE'),
